                      className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono"
                   />
                 </div>
              </div>
            </section>

            <section>
               <h3 className="text-sm font-bold text-katana uppercase tracking-widest mb-6 border-b border-white/5 pb-2">Output Formatting</h3>
               <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Filename Schema</label>
                    <input 
                        type="text"
                        value={settings.filenamePattern}
                        onChange={e => setSettings({...settings, filenamePattern: e.target.value})}
                        className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono text-sm"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                     <div 
                        onClick={() => setSettings({...settings, cleanup: {...cleanup, smartQuotes: !cleanup.smartQuotes}})}
                        className="cursor-pointer bg-white/5 hover:bg-white/10 border border-white/10 p-4 flex justify-between items-center transition-colors"
                     >
                        <span className="text-xs font-bold text-white uppercase tracking-wider">Sanitize Smart Quotes</span>
                        {cleanup.smartQuotes ? <ToggleRight className="text-katana w-6 h-6"/> : <ToggleLeft className="text-steel w-6 h-6"/>}
                     </div>

                     <div 
                        onClick={() => setSettings({...settings, cleanup: {...cleanup, normalizeUnicode: !cleanup.normalizeUnicode}})}
                        className="cursor-pointer bg-white/5 hover:bg-white/10 border border-white/10 p-4 flex justify-between items-center transition-colors"
                     >
                        <span className="text-xs font-bold text-white uppercase tracking-wider">Normalize Unicode (NFKC)</span>
                        {cleanup.normalizeUnicode ? <ToggleRight className="text-katana w-6 h-6"/> : <ToggleLeft className="text-steel w-6 h-6"/>}
                     </div>
                  </div>
               </div>
            </section>

            <div className="pt-6 flex items-center justify-end gap-4 border-t border-white/5">
               {saved && <span className="text-green-500 font-mono text-xs uppercase tracking-widest animate-pulse">&gt;&gt; CONFIG SAVED</span>}
               <button onClick={handleSave} className="bg-katana hover:bg-red-600 text-black px-8 py-3 font-bold uppercase tracking-widest flex items-center gap-2 transition-all hover:shadow-[0_0_15px_rgba(220,38,38,0.5)]">
                 <Save className="w-5 h-5" /> Commit Changes
               </button>
            </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { SiteTemplate } from '../types';
import { fetchJson } from '../src/lib/http';
import { Plus, Trash, Save, Globe, Code, ScanLine, AlertCircle } from 'lucide-react';

export default function Templates() {
  const [templates, setTemplates] = useState<SiteTemplate[]>([]);
  const [editing, setEditing] = useState<Partial<SiteTemplate>>({});
  const [testUrl, setTestUrl] = useState('');
  const [testResult, setTestResult] = useState<{title?: string, contentSnippet?: string} | null>(null);
  const [pickingMode, setPickingMode] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchJson<SiteTemplate[]>('/api/templates')
      .then(setTemplates)
      .catch(e => {
        console.error("Templates fetch error:", e);
        setError(e.message || "Unknown error fetching templates");
      });
  }, []);

  const saveTemplate = async () => {
    if (!editing.domain || !editing.titleSelector || !editing.contentSelector) return;

    try {
        await fetchJson('/api/templates', {
          method: 'POST',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify(editing)
        });

        const data = await fetchJson<SiteTemplate[]>('/api/templates');
        setTemplates(data);
        setEditing({});
        setTestResult(null);
    } catch(e: any) {
        setError(e.message);
    }
  };

  const deleteTemplate = async (id: string) => {
    try {
        await fetchJson(`/api/templates/${id}`, { method: 'DELETE' });
        const data = await fetchJson<SiteTemplate[]>('/api/templates');
        setTemplates(data);
        if (editing.id === id) setEditing({});
    } catch(e: any) {
        setError(e.message);
    }
  };

  const testSelectors = async () => {
    if (!testUrl || !editing.titleSelector || !editing.contentSelector) return;

    try {
        const data = await fetchJson<any>('/api/extract/test-selectors', {
          method: 'POST',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify({ 
              url: testUrl, 
              titleSelector: editing.titleSelector, 
              contentSelector: editing.contentSelector 
          })
        });
        setTestResult(data);
    } catch(e: any) {
        setTestResult({ title: 'Error', contentSnippet: e.message });
    }
  };

  const loadPreview = async () => {
    if(!testUrl) return;
    setPickingMode(true);
  };

  if (error) {
    return (
        <div className="flex flex-col items-center justify-center h-full text-red-500 gap-4 animate-in fade-in">
            <AlertCircle className="w-12 h-12"/>
            <h3 className="font-bold text-lg">PROTOCOL ERROR</h3>
            <div className="text-sm bg-red-950/20 p-4 border border-red-900/50 font-mono">{error}</div>
            <button onClick={() => window.location.reload()} className="bg-white/10 px-6 py-2 uppercase text-xs tracking-widest hover:bg-white/20 text-white">Retry</button>
        </div>
    );
  }

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center border-b border-white/10 pb-4">
        <div>
           <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
              <ScanLine className="text-katana" /> Extraction Protocols
           </h2>
           <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; DOMAIN SPECIFIC SELECTOR CONFIGURATION</p>
        </div>
        <button onClick={() => setEditing({ id: 'new', removeSelectors: [] })} className="bg-white/10 hover:bg-katana hover:text-black text-white px-4 py-2 text-xs font-bold uppercase tracking-widest flex items-center gap-2 transition-all">
           <Plus className="w-4 h-4" /> Initialize New
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        <div className="bg-armor border border-white/10 flex flex-col">
           <div className="p-3 bg-white/5 border-b border-white/5 font-mono text-xs font-bold text-steel uppercase tracking-wider">Stored Domains</div>
           <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-2">
             {templates.length === 0 && <div className="text-center p-8 text-steel text-xs font-mono opacity-50">NO PROTOCOLS DEFINED</div>}
             {templates.map(t => (
               <div key={t.id} className={`p-4 border border-white/5 bg-void hover:border-katana/50 transition-colors group cursor-pointer ${editing.id === t.id ? 'border-katana bg-white/5' : ''}`} onClick={() => setEditing(t)}>
                 <div className="flex justify-between items-start">
                    <div>
                        <div className="font-bold text-white font-mono">{t.domain}</div>
                        <div className="text-[10px] text-steel mt-1 font-mono break-all opacity-50">{t.contentSelector}</div>
                    </div>
                    <button onClick={(e) => { e.stopPropagation(); deleteTemplate(t.id); }} className="text-steel hover:text-katana p-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash className="w-3 h-3"/>
                    </button>
                 </div>
               </div>
             ))}
           </div>
        </div>

        <div className="lg:col-span-2 bg-armor border border-white/10 p-8 overflow-y-auto custom-scrollbar relative">
          {editing.id ? (
            <div className="space-y-8">
              <div className="flex items-center justify-between border-b border-white/10 pb-4">
                 <h3 className="text-lg font-bold text-white uppercase tracking-widest">
                    {editing.id === 'new' ? 'Initialize Protocol' : 'Modify Protocol'}
                 </h3>
                 <span className="text-xs font-mono text-katana animate-pulse">EDIT MODE ACTIVE</span>
              </div>

              <div className="grid grid-cols-1 gap-6">
                <div className="space-y-2">
                  <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Target Domain</label>
                  <input 
                    type="text" 
                    value={editing.domain || ''} 
                    onChange={e => setEditing({...editing, domain: e.target.value})}
                    className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono text-sm placeholder:text-gray-700"
                    placeholder="example.com"
                  />
                </div>

                <div className="p-6 bg-black/40 border border-white/5 relative">
                   <div className="absolute top-0 right-0 p-2 opacity-20"><Code className="w-8 h-8"/></div>
                  <h4 className="text-xs font-bold text-katana mb-4 uppercase tracking-wider">Diagnostics / Testing</h4>
                  <div className="flex gap-2 mb-4">
                     <input 
                       type="text" 
                       placeholder="TEST URL FROM DOMAIN" 
                       value={testUrl}
                       onChange={e => setTestUrl(e.target.value)}
                       className="flex-1 bg-void border border-white/10 p-2 text-white text-xs font-mono focus:border-katana focus:outline-none"
                     />
                     <button onClick={loadPreview} className="bg-white/5 border border-white/10 text-steel hover:text-white hover:bg-white/10 px-4 py-2 text-xs font-mono uppercase">Preview</button>
                  </div>
                  {pickingMode && (
                      <div className="text-[10px] text-steel font-mono border-l-2 border-katana pl-2">
                          &gt;&gt; MANUAL MODE: USE BROWSER DEVTOOLS (F12) TO ACQUIRE SELECTORS.
                      </div>
                  )}
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Title Selector</label>
                    <input 
                      type="text" 
                      value={editing.titleSelector || ''} 
                      onChange={e => setEditing({...editing, titleSelector: e.target.value})}
                      placeholder="h1.entry-title"
                      className="w-full bg-plate border border-white/10 p-3 text-katana focus:border-katana focus:outline-none font-mono text-sm placeholder:text-gray-700"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Content Selector</label>
                    <input 
                      type="text" 
                      value={editing.contentSelector || ''} 
                      onChange={e => setEditing({...editing, contentSelector: e.target.value})}
                      placeholder=".chapter-content"
                      className="w-full bg-plate border border-white/10 p-3 text-katana focus:border-katana focus:outline-none font-mono text-sm placeholder:text-gray-700"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Removal Selectors (CSV)</label>
                   <input 
                      type="text" 
                      value={editing.removeSelectors?.join(', ') || ''} 
                      onChange={e => setEditing({...editing, removeSelectors: e.target.value.split(',').map(s => s.trim())})}
                      placeholder=".ad-banner, .share-buttons"
                      className="w-full bg-plate border border-white/10 p-3 text-red-400 focus:border-katana focus:outline-none font-mono text-sm placeholder:text-gray-700"
                    />
                </div>

                <div className="flex justify-end gap-3 pt-6 border-t border-white/10">
                   <button onClick={testSelectors} className="px-6 py-2 border border-white/10 text-white hover:bg-white/5 text-xs font-bold uppercase tracking-widest">Run Diagnostics</button>
                   <button onClick={saveTemplate} className="px-6 py-2 bg-katana text-black hover:bg-red-500 text-xs font-bold uppercase tracking-widest flex items-center gap-2 transition-all shadow-[0_0_10px_rgba(220,38,38,0.4)]">
                     <Save className="w-4 h-4" /> Save Protocol
                   </button>
                </div>

                {testResult && (
                  <div className="mt-4 p-4 bg-black/50 border-l-4 border-katana text-sm font-mono">
                    <p className="mb-2"><span className="text-steel">TITLE &gt;</span> <span className="text-white">{testResult.title || <span className="text-red-500">NULL</span>}</span></p>
                    <p className="text-steel mb-1">CONTENT PREVIEW &gt;</p>
                    <p className="text-gray-400 italic line-clamp-3 opacity-70 text-xs">{testResult.contentSnippet || 'NO DATA'}</p>
                  </div>
                )}

              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-steel opacity-30">
               <Globe className="w-24 h-24 mb-4 stroke-1" />
               <p className="font-mono text-sm uppercase tracking-widest">Select Protocol to Configure</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import express from 'express';
import cors from 'cors';
import path from 'path';
import { fileURLToPath } from 'url';
import * as extractor from './extractor.ts';
import * as queue from './queue.ts';
import * as storage from './storage.ts';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = 3001; // Changed port to 3001 to avoid conflicts

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Initialize storage (ensure directories)
storage.initStorage().catch(console.error);

// Helper for async route handling
const asyncHandler = (fn: Function) => (req: express.Request, res: express.Response, next: express.NextFunction) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Logging Middleware
app.use((req, res, next) => {
  console.log(`[API] ${req.method} ${req.path}`);
  next();
});

// Health Check
app.get('/api/health', (req, res) => {
  res.json({ ok: true, version: '2.0.45' });
});

// Single Extract
app.post('/api/extract', asyncHandler(async (req: express.Request, res: express.Response) => {
  const { url, templateId } = req.body;
  const result = await extractor.extractSingle(url, templateId);
  res.json(result);
}));

// Test Selectors
app.post('/api/extract/test-selectors', asyncHandler(async (req: express.Request, res: express.Response) => {
  const { url, titleSelector, contentSelector } = req.body;
  const result = await extractor.testSelectors(url, titleSelector, contentSelector);
  res.json(result);
}));

// Batch Operations
app.get('/api/batch/status', (req, res) => {
  res.json(queue.getStatus());
});

app.post('/api/batch/add', asyncHandler(async (req: express.Request, res: express.Response) => {
  queue.addItems(req.body.items);
  res.json({ success: true });
}));

app.post('/api/batch/start', asyncHandler(async (req: express.Request, res: express.Response) => {
  await queue.startProcessing();
  res.json({ success: true });
}));

app.post('/api/batch/stop', (req, res) => {
  queue.stopProcessing();
  res.json({ success: true });
}));

app.post('/api/batch/clear', (req, res) => {
  queue.clearQueue();
  res.json({ success: true });
}));

app.get('/api/batch/download', asyncHandler(async (req: express.Request, res: express.Response) => {
  const zipBuffer = await queue.createBatchZip();
  res.set('Content-Type', 'application/zip');
  res.set('Content-Disposition', 'attachment; filename=chapters.zip');
  res.send(zipBuffer);
}));

// Templates Routes
app.get('/api/templates', asyncHandler(async (req: express.Request, res: express.Response) => {
  const data = await storage.getTemplates();
  res.json(data);
}));

app.post('/api/templates', asyncHandler(async (req: express.Request, res: express.Response) => {
  const template = req.body;
  const templates = await storage.getTemplates();

  if (template.id === 'new' || !template.id) {
    template.id = Math.random().toString(36).substr(2, 9);
    templates.push(template);
  } else {
    const idx = templates.findIndex(t => t.id === template.id);
    if (idx >= 0) templates[idx] = template;
    else templates.push(template);
  }

  await storage.saveTemplates(templates);
  res.json({ success: true });
}));

app.delete('/api/templates/:id', asyncHandler(async (req: express.Request, res: express.Response) => {
  const { id } = req.params;
  let templates = await storage.getTemplates();
  templates = templates.filter(t => t.id !== id);
  await storage.saveTemplates(templates);
  res.json({ success: true });
}));

// Settings Routes
app.get('/api/settings', asyncHandler(async (req: express.Request, res: express.Response) => {
  const data = await storage.getSettings();
  res.json(data);
}));

app.post('/api/settings', asyncHandler(async (req: express.Request, res: express.Response) => {
  const newSettings = req.body;
  const current = await storage.getSettings();
  const merged = { ...current, ...newSettings };
  await storage.saveSettings(merged);
  res.json({ success: true });
}));

// Serve static files from the dist directory
const distPath = path.resolve(__dirname, '..', 'dist');
app.use(express.static(distPath));

// Fallback for SPA routing
app.get('*', (req, res, next) => {
  if (req.path.startsWith('/api')) {
    // If it's an API request that didn't match above, it's a 404
    console.log(`[API] 404 Not Found: ${req.path}`);
    res.status(404).json({ error: `Route not found: ${req.path}` });
  } else {
    // Otherwise serve index.html
    res.sendFile(path.join(distPath, 'index.html'), (err) => {
      if (err) {
         if (!res.headersSent) res.status(404).send('Frontend not built. Run "npm run build".');
      }
    });
  }
});

// Global Error Handler
app.use((err: any, req: express.Request, res: express.Response, next: express.NextFunction) => {
  console.error("Global Server Error:", err);
  if (!res.headersSent) {
    res.status(500).json({ 
        error: err.message || 'Internal Server Error',
        stack: process.env.NODE_ENV === 'development' ? err.stack : undefined
    });
  }
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`Server running at http://localhost:${PORT}`);
  console.log(`Storage location: ${path.join(__dirname, '..', 'data')}`);
});

