// Resolve data directory relative to this file (server/storage.ts -> ../data)
const DATA_DIR = path.join(__dirname, '..', 'data');
const TEMPLATES_FILE = path.join(DATA_DIR, 'templates.json');
const SETTINGS_FILE = path.join(DATA_DIR, 'settings.json');

const DEFAULT_SETTINGS: AppSettings = {
  concurrency: 2,
  rateLimit: 10,
  outputFolder: './output',
  filenamePattern: '{series}/{vol}/{ch} {title}.txt',
  cleanup: {
    removeImages: true,
    smartQuotes: true,
    normalizeUnicode: true
  }
};

async function ensureDir(dir: string) {
  try {
    await fsp.mkdir(dir, { recursive: true });
  } catch (e) {
    // ignore if exists
  }
}

async function readJson<T>(file: string, defaultVal: T): Promise<T> {
  try {
    const data = await fsp.readFile(file, 'utf-8');
    if (!data.trim()) return defaultVal;
    return JSON.parse(data);
  } catch (e) {
    // If file doesn't exist or is invalid JSON, return default
    return defaultVal;
  }
}

async function writeJson(file: string, data: any) {
  await ensureDir(path.dirname(file));
  await fsp.writeFile(file, JSON.stringify(data, null, 2), 'utf-8');
}

export async function initStorage() {
  await ensureDir(DATA_DIR);
  console.log(`[Storage] Initialized at ${DATA_DIR}`);
}

export async function getSettings(): Promise<AppSettings> {
  const loaded = await readJson<Partial<AppSettings>>(SETTINGS_FILE, {});

  // Deep merge to ensure all properties exist
  return {
    ...DEFAULT_SETTINGS,
    ...loaded,
    cleanup: {
      ...DEFAULT_SETTINGS.cleanup,
      ...(loaded.cleanup || {})
    }
  };
}

export async function saveSettings(settings: AppSettings) {
  await writeJson(SETTINGS_FILE, settings);
}

export async function getTemplates(): Promise<SiteTemplate[]> {
  return readJson<SiteTemplate[]>(TEMPLATES_FILE, []);
}

export async function saveTemplates(templates: SiteTemplate[]) {
  await writeJson(TEMPLATES_FILE, templates);
}

import * as cheerio from 'cheerio';
import { Readability } from '@mozilla/readability';
import { JSDOM } from 'jsdom';
import { chromium } from 'playwright';
import * as storage from './storage.ts';
import type { SiteTemplate, AppSettings } from '../types.ts';

export async function extractSingle(url: string, templateId?: string) {
  const settings = await storage.getSettings();
  const templates = await storage.getTemplates();

  let html = '';

  // 1. Fetch
  try {
    // Basic fetch
    const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    html = await res.text();
  } catch (e) {
    console.log('Static fetch failed, trying Playwright...');
    const browser = await chromium.launch();
    const page = await browser.newPage();
    await page.goto(url, { waitUntil: 'domcontentloaded' });
    html = await page.content();
    await browser.close();
  }

  // 2. Parse
  const $ = cheerio.load(html);

  // 3. Template vs Auto
  let template: SiteTemplate | undefined;

  if (templateId) {
    template = templates.find(t => t.id === templateId);
  } else {
    // Auto-match
    try {
        const domain = new URL(url).hostname;
        template = templates.find(t => domain.includes(t.domain));
    } catch {}
  }

  let title = '';
  let content = '';

  if (template) {
    // Manual Mode
    if (template.removeSelectors) {
      template.removeSelectors.forEach(s => $(s).remove());
    }
    title = $(template.titleSelector).first().text();
    const contentEl = $(template.contentSelector).first();
    content = formatContent($, contentEl);
  } else {
    // Auto Mode (Readability)
    const dom = new JSDOM(html, { url });
    const reader = new Readability(dom.window.document);
    const article = reader.parse();
    if (!article) throw new Error('Could not auto-extract content.');

    title = article.title;
    const $auto = cheerio.load(article.content);
    content = formatContent($auto, $auto('body'));
  }

  // 4. Cleanup
  title = cleanText(title, settings);
  content = cleanText(content, settings);

  return { title, content, url };
}

function formatContent($: cheerio.CheerioAPI, el: cheerio.Cheerio<any>): string {
    let textParts: string[] = [];
    el.find('p, div, h1, h2, h3, h4, h5, h6, li').each((_, elem) => {
        const text = $(elem).text().trim();
        if (text) textParts.push(text);
    });

    if (textParts.length === 0) {
        return el.text().trim();
    }
    return textParts.join('\n\n');
}

function cleanText(text: string, settings: AppSettings): string {
  if (!text) return '';

  if (settings.cleanup.normalizeUnicode) {
    text = text.normalize('NFKC');
  }

  if (settings.cleanup.smartQuotes) {
    text = text.replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"');
  }

  return text.replace(/\n{3,}/g, '\n\n').trim();
}

export async function testSelectors(url: string, titleSelector: string, contentSelector: string) {
    try {
        const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
        const html = await res.text();
        const $ = cheerio.load(html);
        const title = $(titleSelector).first().text().trim();
        const contentEl = $(contentSelector).first();
        const content = contentEl.text().trim().substring(0, 200) + '...';
        return { title, contentSnippet: content };
    } catch(e: any) {
        return { title: 'Error fetching', contentSnippet: e.message };
    }
}

import type { BatchItem } from '../types.ts';
import * as extractor from './extractor.ts';
import * as storage from './storage.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';
import { Buffer } from 'buffer';

// Queue logic needs to handle state
interface QueueItem {
    id: string;
    url: string;
    status: 'pending' | 'processing' | 'success' | 'failed';
    result?: any;
    retries: number;
}

let queue: QueueItem[] = [];
let isProcessing = false;

export function getStatus() {
    return { queue, isProcessing };
}

export function addItems(items: QueueItem[]) {
    queue.push(...items);
}

export function clearQueue() {
    if (!isProcessing) queue = [];
}

export async function startProcessing() {
    if (isProcessing) return;
    isProcessing = true;
    processQueue();
}

export function stopProcessing() {
    isProcessing = false;
}

async function processQueue() {
    while (isProcessing) {
        const pending = queue.find(i => i.status === 'pending');
        if (!pending) break;

        const config = await storage.getSettings();

        pending.status = 'processing';

        try {
            // Rate limit delay
            const delay = 60000 / (config.rateLimit || 10);
            await new Promise(r => setTimeout(r, delay));

            const result = await extractor.extractSingle(pending.url);
            pending.result = {
                ...result,
                filename: generateFilename(result.title),
                wordCount: result.content.split(/\s+/).length
            };
            pending.status = 'success';
        } catch (e: any) {
            pending.status = 'failed';
            pending.result = { error: e.message };
            console.error(`Error processing ${pending.url}:`, e);
        }
    }
    isProcessing = false;
}

function generateFilename(title: string) {
    return sanitize(`${title}.txt`);
}

export async function createBatchZip() {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    successItems.forEach(item => {
        if(item.result) {
            const content = `${item.result.title}\n${item.url}\n\n${item.result.content}`;
            const fname = sanitize(`${item.result.title.substring(0, 50)}.txt`);
            zip.addFile(fname, Buffer.from(content, 'utf8'));
        }
    });

    return zip.toBuffer();
}

export const API_BASE = import.meta.env.DEV ? 'http://localhost:8787' : '';

export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
  const fullUrl = url.startsWith('http') ? url : `${API_BASE}${url}`;

  try {
    const res = await fetch(fullUrl, init);
    const text = await res.text();

    if (!res.ok) {
      let msg = `HTTP ${res.status}`;
      try {
        const j = text ? JSON.parse(text) : null;
        if (j?.error) msg = j.error;
        else if (j?.message) msg = j.message;
      } catch {}
      throw new Error(msg);
    }

    if (!text.trim()) {
       // If empty body on success, return empty object
       return {} as T; 
    }

    try {
        return JSON.parse(text) as T;
    } catch(e) {
        throw new Error(`Invalid JSON response: ${text.substring(0, 50)}...`);
    }
  } catch (error: any) {
    // If it's a network error (like connection refused), give a better message
    if (error.message === 'Failed to fetch') {
      throw new Error('Connection to backend failed. Is the server running on port 8787?');
    }
    throw error;
  }
}

import React, { useState } from 'react';
import { Play, Copy, Download, Loader2, AlertCircle, Terminal, Cpu } from 'lucide-react';
import { Chapter } from '../types';
import { fetchJson } from '../src/lib/http';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<Chapter | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await fetchJson<Chapter>('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });
      setResult(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (result) {
      navigator.clipboard.writeText(`${result.title}\n\n${result.content}`);
    }
  };

  const downloadTxt = () => {
    if (!result) return;
    const element = document.createElement("a");
    const file = new Blob([`${result.title}\n\nSource: ${result.url}\n\n${result.content}`], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `${result.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col gap-1 border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase">Single Target Extraction</h2>
        <p className="text-steel font-mono text-sm">Initialize sequence for singular web entity.</p>
      </div>

      <div className="bg-armor border border-white/10 p-1">
        <div className="flex gap-0">
          <div className="flex-1 bg-plate relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Terminal className="h-4 w-4 text-steel group-focus-within:text-katana transition-colors" />
            </div>
            <input
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="ENTER TARGET URL..."
              className="w-full bg-transparent text-white p-4 pl-12 focus:outline-none font-mono text-sm placeholder:text-gray-700"
            />
          </div>
          <button
            onClick={handleExtract}
            disabled={loading || !url}
            className="bg-katana hover:bg-red-600 text-black px-8 py-4 font-bold uppercase tracking-widest disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 transition-all hover:shadow-[0_0_15px_#DC2626]"
          >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
            Execute
          </button>
        </div>
      </div>

      {error && (
        <div className="bg-red-950/30 text-red-400 p-4 border border-red-900/50 flex items-center gap-3 font-mono text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>&gt; ERROR: {error}</p>
        </div>
      )}

      {result && (
        <div className="bg-armor border border-white/10 shadow-2xl overflow-hidden relative">
          <div className="absolute top-0 right-0 p-2 opacity-10">
             <Cpu className="w-24 h-24 text-white" />
          </div>

          <div className="bg-black/40 px-6 py-4 border-b border-white/5 flex justify-between items-center backdrop-blur-sm">
            <div className="z-10">
              <h3 className="font-bold text-white text-lg tracking-wide">{result.title}</h3>
              <p className="text-[10px] text-katana font-mono uppercase tracking-wider">{result.url}</p>
            </div>
            <div className="flex gap-2 z-10">
              <button onClick={copyToClipboard} className="p-2 text-steel hover:text-white hover:bg-white/10 transition-colors border border-transparent hover:border-white/10" title="Copy Buffer">
                <Copy className="w-4 h-4" />
              </button>
              <button onClick={downloadTxt} className="p-2 text-steel hover:text-katana hover:bg-red-950/30 transition-colors border border-transparent hover:border-red-900/50" title="Export Data">
                <Download className="w-4 h-4" />
              </button>
            </div>
          </div>
          <div className="p-8 max-h-[600px] overflow-y-auto custom-scrollbar">
            <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-300 font-light">
              {result.content}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Play, Pause, Download, Loader2, CheckCircle, XCircle, List, TerminalSquare } from 'lucide-react';
import { BatchItem } from '../types';
import { fetchJson, API_BASE } from '../src/lib/http';

export default function BatchExtract() {
  const [urls, setUrls] = useState('');
  const [queue, setQueue] = useState<BatchItem[]>([]);
  const [processing, setProcessing] = useState(false);
  const [progress, setProgress] = useState({ total: 0, completed: 0, failed: 0 });

  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (processing) {
      interval = setInterval(fetchQueueStatus, 1000);
    }
    return () => clearInterval(interval);
  }, [processing]);

  const fetchQueueStatus = async () => {
    try {
      const data = await fetchJson<any>('/api/batch/status');
      setQueue(data.queue);
      setProcessing(data.isProcessing);

      const completed = data.queue.filter((i: BatchItem) => i.status === 'success').length;
      const failed = data.queue.filter((i: BatchItem) => i.status === 'failed').length;
      setProgress({ total: data.queue.length, completed, failed });

    } catch (e) {
      console.error("Failed to fetch status", e);
    }
  };

  const addToQueue = async () => {
    if (!urls.trim()) return;
    const newItems = urls.split('\n').filter(u => u.trim()).map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url: url.trim(),
      status: 'pending' as const,
      retries: 0
    }));

    try {
      await fetchJson('/api/batch/add', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ items: newItems })
      });
      fetchQueueStatus();
      setUrls('');
    } catch (e) {
      console.error("Failed to add to queue", e);
    }
  };

  const startBatch = async () => {
    setProcessing(true);
    try {
      await fetchJson('/api/batch/start', { method: 'POST' });
    } catch(e) {
      setProcessing(false);
      console.error("Failed to start batch", e);
    }
  };

  const stopBatch = async () => {
    setProcessing(false);
    try {
      await fetchJson('/api/batch/stop', { method: 'POST' });
    } catch(e) {
      console.error("Failed to stop batch", e);
    }
  };

  const clearQueue = async () => {
    try {
      await fetchJson('/api/batch/clear', { method: 'POST' });
      fetchQueueStatus();
    } catch(e) {
      console.error("Failed to clear queue", e);
    }
  };

  const downloadZip = () => {
     window.location.href = `${API_BASE}/api/batch/download`;
  };

  return (
    <div className="space-y-6 h-full flex flex-col animate-in fade-in duration-500">
      <div className="flex justify-between items-end border-b border-white/10 pb-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
             <List className="text-katana" /> Batch Processor
          </h2>
          <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; AWAITING URL INPUT STREAM</p>
        </div>
        <div className="flex gap-3">
           {processing ? (
             <button onClick={stopBatch} className="bg-yellow-600/20 border border-yellow-600/50 text-yellow-500 hover:bg-yellow-600/30 px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all">
               <Pause className="w-4 h-4" /> Halt
             </button>
           ) : (
             <button onClick={startBatch} disabled={queue.length === 0} className="bg-katana hover:bg-red-600 text-black px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30 disabled:cursor-not-allowed">
               <Play className="w-4 h-4 fill-current" /> Engage
             </button>
           )}
           <button onClick={downloadZip} disabled={progress.completed === 0} className="border border-white/20 text-white hover:border-katana hover:text-katana px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30 disabled:cursor-not-allowed">
             <Download className="w-4 h-4" /> Archive
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        {/* Input Area */}
        <div className="bg-armor border border-white/10 p-1 flex flex-col h-full">
          <div className="bg-white/5 p-3 border-b border-white/5">
             <label className="font-mono text-xs font-bold text-katana uppercase tracking-wider">Input Stream</label>
          </div>
          <textarea
            className="flex-1 w-full p-4 bg-void text-steel focus:outline-none focus:bg-black font-mono text-xs resize-none placeholder:text-gray-800"
            placeholder="PASTE URLS [ONE PER LINE]..."
            value={urls}
            onChange={e => setUrls(e.target.value)}
          />
          <button onClick={addToQueue} className="w-full bg-white/5 text-white py-3 hover:bg-katana hover:text-black border-t border-white/10 font-mono text-xs uppercase tracking-widest flex justify-center items-center gap-2 transition-colors">
            <Plus className="w-4 h-4" /> Inject to Queue
          </button>
        </div>

        {/* Queue List */}
        <div className="lg:col-span-2 bg-armor border border-white/10 flex flex-col min-h-0 relative overflow-hidden">
          {/* Decorative Grid Background */}
          <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

          <div className="p-4 border-b border-white/10 flex justify-between items-center bg-black/40 backdrop-blur z-10">
             <div className="flex gap-6 font-mono text-xs">
               <span className="text-steel">TOTAL: <span className="text-white">{progress.total}</span></span>
               <span className="text-steel">SUCCESS: <span className="text-green-500">{progress.completed}</span></span>
               <span className="text-steel">FAILED: <span className="text-katana">{progress.failed}</span></span>
             </div>
             <button onClick={clearQueue} className="text-steel hover:text-katana transition-colors">
               <Trash2 className="w-4 h-4" />
             </button>
          </div>

          <div className="flex-1 overflow-y-auto p-0 z-10 custom-scrollbar">
            <table className="w-full text-left text-sm">
              <thead className="bg-white/5 text-steel font-mono text-xs uppercase tracking-wider border-b border-white/5 sticky top-0">
                <tr>
                  <th className="px-6 py-3 w-32">State</th>
                  <th className="px-6 py-3">Payload Identifier</th>
                  <th className="px-6 py-3 text-right">Data</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5 font-mono text-xs">
                {queue.map((item) => (
                  <tr key={item.id} className="hover:bg-white/5 transition-colors group">
                    <td className="px-6 py-3">
                      {item.status === 'pending' && <span className="text-steel flex items-center gap-2">WAITING...</span>}
                      {item.status === 'processing' && <span className="text-blue-400 flex items-center gap-2"><Loader2 className="w-3 h-3 animate-spin"/> PROCESSING</span>}
                      {item.status === 'success' && <span className="text-green-500 flex items-center gap-2"><CheckCircle className="w-3 h-3"/> COMPLETE</span>}
                      {item.status === 'failed' && <span className="text-katana flex items-center gap-2"><XCircle className="w-3 h-3"/> FAILURE</span>}
                    </td>
                    <td className="px-6 py-3">
                      <div className="font-medium text-white truncate max-w-xs md:max-w-md group-hover:text-katana transition-colors">
                        {item.result?.title || item.url}
                      </div>
                      {item.result?.error && <div className="text-[10px] text-red-500 mt-1">&gt;&gt; ERR: {item.result.error}</div>}
                    </td>
                    <td className="px-6 py-3 text-right text-steel">
                      {item.result?.wordCount ? `${item.result.wordCount} words` : '-'}
                    </td>
                  </tr>
                ))}
                {queue.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-6 py-20 text-center">
                      <div className="flex flex-col items-center gap-3 opacity-20">
                         <TerminalSquare className="w-12 h-12" />
                         <span className="font-mono text-sm uppercase tracking-widest">Buffer Empty</span>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

